        merkle_tree_pubkey,
        output_queue_pubkey,
        &payer,
        Some(new_keypair_queue.pubkey()),
        TestMode::InvalidOutputQueue,
    )
    .await;
    assert_rpc_error(
        result,
        0,
        MerkleTreeMetadataError::MerkleTreeAndQueueNotAssociated.into(),
