let create_cpi_context_instruction = create_account_instruction(
    &payer.pubkey(),
    ProtocolConfig::default().cpi_context_size as usize,
    rent_cpi_config,
    &Pubkey::from(light_sdk::constants::LIGHT_SYSTEM_PROGRAM_ID),
    Some(cpi_context_keypair),
);
let instruction = if registry {
    create_initialize_batched_merkle_tree_instruction(
        authority.pubkey(),
        merkle_tree_keypair.pubkey(),
        queue_keypair.pubkey(),
        cpi_context_keypair.pubkey(),
        params,
    )
} else {
    let instruction = account_compression::instruction::InitializeBatchedStateMerkleTree {
        bytes: params.try_to_vec().unwrap(),
    };
    let accounts = account_compression::accounts::InitializeBatchedStateMerkleTreeAndQueue {
        authority: payer.pubkey(),
        merkle_tree: merkle_tree_keypair.pubkey(),
        queue: queue_keypair.pubkey(),
        registered_program_pda: None,
    };

    Instruction {
        program_id: account_compression::ID,
        accounts: accounts.to_account_metas(Some(true)),
        data: instruction.data(),
    }
};

let mut signers: Vec<&Keypair> = vec![payer, merkle_tree_keypair, queue_keypair, cpi_context_keypair];
if registry && authority.pubkey() != payer.pubkey() {
    signers.push(authority);
}

rpc.create_and_send_transaction(
    &[
        create_mt_account_ix,
        create_queue_account_ix,
        create_cpi_context_instruction,
        instruction,
    ],
    &payer.pubkey(),
    &signers,
)
.await

async fn add_address_merkle_tree_v2<R: Rpc>(
    &mut self,
    rpc: &mut R,
    merkle_tree_keypair: &Keypair,
    queue_keypair: &Keypair,
    _owning_program_id: Option<Pubkey>,
) -> Result<AddressMerkleTreeAccounts, RpcError> {
    info!(
        "Adding address merkle tree accounts v2 {:?}",
        merkle_tree_keypair.pubkey()
    );

    let params = light_batched_merkle_tree::initialize_address_tree::InitAddressTreeAccountsInstructionData::test_default();

    info!(
        "Creating batched address merkle tree {:?}",
        merkle_tree_keypair.pubkey()
    );
    create_batch_address_merkle_tree(rpc, &self.payer, &self.payer, merkle_tree_keypair, params).await?;
    info!(
        "Batched address merkle tree created {:?}",
        merkle_tree_keypair.pubkey()
    );

    let accounts = self.add_address_merkle_tree_accounts(
        merkle_tree_keypair,
        queue_keypair,
        _owning_program_id,
    );
    Ok(accounts)

