                    0,
                    0,
                    DEFAULT_BATCH_ROOT_HISTORY_LEN,

                ));
                (FeeConfig::test_batched().state_merkle_tree_rollover as i64,merkle_tree, Some(params.output_queue_batch_size as usize))
            }

