        }
        output_compressed_accounts[0].lamports += remainder;
        (output_compressed_accounts, output_merkle_tree_pubkeys)
    } else {
        (Vec::new(), Vec::new())
    };
    let (remaining_accounts, inputs_struct) = create_invoke_instruction_data_and_remaining_accounts(
