            rpc,
            merkle_tree_keypair,
            queue_keypair,
            owning_program_id,
            Some(
                Keypair::try_from(FORESTER_TEST_KEYPAIR.as_slice())
                    .unwrap()
                    .pubkey(),
            ), // std forester, we now need to set it.
            &config,
            &AddressQueueConfig::default(),
            0,
        )
        .await?;

        let accounts = <TestIndexer as TestIndexerExtensions>::add_address_merkle_tree_accounts(
