                            }
                            (true, false) => {
                                // v2 state trees with v1 address trees (height 26)
                                return Err(IndexerError::MixedTreeVersions {
                                    state_version: "v2 (state tree)".to_string(),
                                    address_version: "v1 (address tree height 26)".to_string(),
                                });
                            }
