            .compressed_accounts
            .iter()
            .filter(|x| {
                x.compressed_account.owner.to_bytes() == payer_pubkey.to_bytes()
                    && x.merkle_context.queue_pubkey.to_bytes() == output_queue_pubkey.to_bytes()
            })
            .next_back()
