            .tree_info
            .to_light_merkle_context(compressed_account_with_context_1.leaf_index, true);

        let instruction = create_invoke_instruction(
            &payer_pubkey,
            &payer_pubkey,
            &[account_with_context.compressed_account],
            &output_compressed_accounts,
            &[light_merkle_context],
